import xml.etree.ElementTree as ET

def parse_config(file):
    tree = ET.parse(file)
    root = tree.getroot()

    settings = {}
    for elem in root:
        key = elem.tag.split('}')[-1]  # assuming the XML tags are namespace-qualified and end with the element name
        settings[key] = elem.text

    return settings